    17→function pointsToPath(pts: number[][]): string {
    18→  if (pts.length < 2) return "";
    19→  let d = `M ${pts[0][0]} ${pts[0][1]}`;
    20→  for (let i = 1; i < pts.length; i++) {
    21→    const [x0, y0] = pts[i - 1];
    22→    const [x1, y1] = pts[i];
    23→    const cpx = (x0 + x1) / 2;
    24→    d += ` C ${cpx} ${y0}, ${cpx} ${y1}, ${x1} ${y1}`;
    25→  }
    26→  return d;
    27→}
