    45→  const [val, setVal] = useState(0);
    46→  useEffect(() => {
    47→    const t = setTimeout(() => {
    48→      const start = Date.now();
    49→      const tick = () => {
    50→        const elapsed = (Date.now() - start) / 1000;
    51→        const progress = Math.min(elapsed / duration, 1);
    52→        const eased = 1 - Math.pow(1 - progress, 3);
    53→        setVal(Math.round(eased * target));
    54→        if (progress < 1) requestAnimationFrame(tick);
    55→      };
    56→      requestAnimationFrame(tick);
    57→    }, delay * 1000);
    58→    return () => clearTimeout(t);
    59→  }, [target, duration, delay]);
    60→  return <>{val.toLocaleString()}{suffix}</>;
    61→}
